const lead = $input.item.json || {};
let score = 0;
let products = [];
let tipo = (lead.tipo_lead || '').toLowerCase();
let dor = (lead.dor_principal || '').toLowerCase();
let regiao = (lead.regiao || lead.bairro || lead.cidade || '').toLowerCase();

// 1. Tipo e Produtos
if (tipo.includes('condomínio') || tipo.includes('condominio')) {
    score += 20;
    products.push('DL Guardião', 'Fortress', 'Gatekeeper', 'DL Acqua', 'DL Partner', 'DL Volt');
} else if (tipo.includes('escola') || tipo.includes('colegio') || tipo.includes('colégio')) {
    score += 20;
    products.push('CFTV', 'Prevenção de Incêndio', 'Controle de Acesso');
} else if (tipo.includes('restaurante') || tipo.includes('lanchonete')) {
    score += 20;
    products.push('Mult Grill', 'Infraestrutura Elétrica');
}

// 2. Presença Digital
if (lead.tem_redes_sociais || lead.instagram || lead.facebook) score += 10;
if (lead.site_ruim === true || lead.site_desatualizado === true) score += 10;

// 3. Dores
if (dor.includes('segurança') || dor.includes('energia') || dor.includes('cftv') || dor.includes('roubo') || dor.includes('incêndio') || dor.includes('conta alta')) score += 20;

// 4. Contato
if (lead.telefone_publico || lead.telefone) score += 10;

// 5. Região
const regioes_prioritarias = ['barra', 'recreio', 'jacarepagua', 'jacarepaguá', 'sul', 'centro', 'copacabana', 'ipanema', 'leblon', 'botafogo', 'flamengo'];
if (regioes_prioritarias.some(r => regiao.includes(r))) {
    score += 10;
}

// Preparar payload de retorno
return {
    json: {
        ...lead,
        score_oportunidade: score,
        produto_recomendado: products
    }
};

